1	/**
2	 * Structural operations under the two-regime algebra
3	 * (docs/research/04-open-questions.md):
4	 *
5	 *   HEADINGS         indent/outdent = level ± 1, whole subtree shifts,
6	 *                    hierarchy re-derives from levels; reject at h1/h6.
7	 *   EVERYTHING ELSE  indent = child of previous sibling, outdent =
8	 *                    brother→uncle; encoding recomputed from context.
9	 *
10	 * Implementation strategy: each op performs line surgery on the tree, then
11	 * the canonical result is parse(encode(surgery)) — closure with the mapping
12	 * holds by construction, and the inverse-law tests guard semantics.
13	 *
14	 * Markdown-imposed rejections beyond the bounds:
15	 * - content cannot become a *sibling of a heading section it is inside*
16	 *   (heading scope is positional), so outdent out of a heading is rejected;
17	 * - only list items can nest under a paragraph, and nothing nests under an
18	 *   atom;
19	 * - reordering across the heading/content divide (or between heading
20	 *   levels) has no positional encoding and is rejected.
21	 */
22	
23	import type { OutlineDoc, OutlineNode } from './model';
24	import { findPath, isAtom, nodeAt, updateSiblings } from './model';
25	import { encode, encodeLines } from './encode';
26	import { parse, indentWidth } from './parse';
27	import type { Edit, OpResult } from './result';
28	import { accept, diffLines, reject } from './result';
29	import { encodingKindAtDestination } from './rules';
30	import { childBaseCol, headingWithLevel, markerWidth, reencodeForDestination } from './reencode';
31	
32	export interface OpOutput {
33	  readonly doc: OutlineDoc;
34	  readonly edits: readonly Edit[];
35	  /**
36	   * Where the operated-on node landed: its first line (0-based, in the new
37	   * text) and the character offset of its content start (after indentation
38	   * and any list/heading marker) — ready to become an editor cursor.
39	   */
40	  readonly cursor: { readonly line: number; readonly ch: number };
41	}
42	
43	const isContent = (node: OutlineNode): boolean =>
44	  node.kind === 'paragraph' || node.kind === 'list-item';
45	
46	function childrenAt(doc: OutlineDoc, path: readonly number[]): readonly OutlineNode[] {
47	  return path.length === 0 ? doc.children : (nodeAt(doc, path)?.children ?? []);
48	}
49	
50	/** Char offset where a line's content starts (after indent + marker). */
51	function contentColumnCh(line: string): number {
52	  const match = /^[ \t]*(?:(?:[-+*]|\d{1,9}[.)])[ \t]+)?(?:#{1,6}[ \t]+)?/.exec(line);
53	  return match ? match[0].length : 0;
54	}
55	
56	/** Start line of a node in a doc's encoding (ids preserved from surgery). */
57	function startLineOf(doc: OutlineDoc, id: number): number {
58	  let line = doc.preamble.length;
59	  let found = -1;
60	  const walk = (node: OutlineNode): void => {
61	    if (found !== -1) return;
62	    if (node.id === id) {
63	      found = line;
64	      return;
65	    }
66	    line += node.lines.length + node.trailingGap.length;
67	    node.children.forEach(walk);
68	  };
69	  doc.children.forEach(walk);
70	  return found === -1 ? 0 : found;
71	}
72	
73	function finalize(
74	  oldDoc: OutlineDoc,
75	  surgery: OutlineDoc,
76	  subjectId: number,
77	): OpResult<OpOutput> {
78	  const normalized = normalizeBoundaries(surgery);
79	  const text = encode(normalized);
80	  const lines = text === '' ? [] : text.split('\n');
81	  const subjectLine = startLineOf(normalized, subjectId);
82	  return accept({
83	    doc: parse(text),
84	    edits: diffLines(encodeLines(oldDoc), lines),
85	    cursor: { line: subjectLine, ch: contentColumnCh(lines[subjectLine] ?? '') },
86	  });
87	}
88	
89	// ---------------------------------------------------------------- headings
90	
91	function shiftHeadingLevels(node: OutlineNode, delta: number): OutlineNode {
92	  const self =
93	    node.kind === 'heading' ? headingWithLevel(node, (node.level ?? 1) + delta) : node;
94	  return { ...self, children: self.children.map((child) => shiftHeadingLevels(child, delta)) };
95	}
96	
97	function maxHeadingLevel(node: OutlineNode): number {
98	  let max = node.kind === 'heading' ? (node.level ?? 1) : 0;
99	  for (const child of node.children) max = Math.max(max, maxHeadingLevel(child));
100	  return max;
101	}
102	
103	function headingLevelOp(
104	  doc: OutlineDoc,
105	  path: readonly number[],
106	  node: OutlineNode,
107	  delta: number,
108	): OpResult<OpOutput> {
109	  if (delta > 0 && maxHeadingLevel(node) >= 6) return reject('at-h6-bound');
110	  if (delta < 0 && (node.level ?? 1) <= 1) return reject('at-h1-bound');
111	  const surgery = updateSiblings(doc, path.slice(0, -1), (siblings) =>
112	    siblings.map((sibling, i) =>
113	      i === path[path.length - 1] ? shiftHeadingLevels(sibling, delta) : sibling,
114	    ),
115	  );
116	  return finalize(doc, surgery, node.id);
117	}
118	
119	// ------------------------------------------------------- separation repair
120	
121	function subtreeFinalNode(node: OutlineNode): OutlineNode {
122	  const last = node.children[node.children.length - 1];
123	  return last ? subtreeFinalNode(last) : node;
124	}
125	
126	function appendFinalGap(node: OutlineNode): OutlineNode {
127	  const last = node.children[node.children.length - 1];
128	  if (!last) return { ...node, trailingGap: [...node.trailingGap, ''] };
129	  return {
130	    ...node,
131	    children: [...node.children.slice(0, -1), appendFinalGap(last)],
132	  };
133	}
134	
135	function needsBlankBetween(prev: OutlineNode, next: OutlineNode): boolean {
136	  const leaf = subtreeFinalNode(prev);
137	  if (leaf.trailingGap.length > 0) return false;
138	  if (leaf.kind === 'paragraph') {
139	    return (
140	      next.kind === 'paragraph' ||
141	      next.kind === 'html' ||
142	      (next.kind === 'heading' && next.setext === true) ||
143	      (next.kind === 'hr' && (next.lines[0] ?? '').includes('-'))
144	    );
145	  }
146	  if (leaf.kind === 'list-item') {
147	    const contentCol = indentWidth(leaf.lines[0] ?? '') + markerWidth(leaf);
148	    return (
149	      (next.kind === 'paragraph' || next.kind === 'html') &&
150	      indentWidth(next.lines[0] ?? '') >= contentCol
151	    );
152	  }
153	  return false;
154	}
155	
156	/**
157	 * Insert the blank lines that keep adjacent blocks from merging on reparse.
158	 * On any tree that came out of `parse` this is a no-op — such boundaries
159	 * cannot exist there — so it only ever touches op-created seams.
160	 */
161	function normalizeBoundaries(doc: OutlineDoc): OutlineDoc {
162	  const fixList = (nodes: readonly OutlineNode[]): readonly OutlineNode[] => {
163	    const out = nodes.map((node) => {
164	      let fixed: OutlineNode = { ...node, children: fixList(node.children) };
165	      const firstChild = fixed.children[0];
166	      if (
167	        firstChild &&
168	        fixed.kind === 'list-item' &&
169	        fixed.trailingGap.length === 0 &&
170	        (firstChild.kind === 'paragraph' || firstChild.kind === 'html')
171	      ) {
172	        fixed = { ...fixed, trailingGap: [''] };
173	      }
174	      return fixed;
175	    });
176	    return out.map((node, i) =>
177	      i < out.length - 1 && needsBlankBetween(node, out[i + 1]!) ? appendFinalGap(node) : node,
178	    );
179	  };
180	  return { ...doc, children: fixList(doc.children) };
181	}
182	
183	// ------------------------------------------------------ ordered renumbering
184	
185	const ORDERED_MARKER_RE = /^([ \t]*)\d{1,9}([.)])/;
186	
187	/**
188	 * Renumber maximal runs of ordered items. A run keeps its start number
189	 * (taken as the minimum present, so a swap doesn't inherit the moved item's
190	 * number while `5. 6. 7.`-style lists keep starting at 5).
191	 */
192	function renumberOrdered(nodes: readonly OutlineNode[]): readonly OutlineNode[] {
193	  const isOrdered = (n: OutlineNode): boolean =>
194	    n.kind === 'list-item' && n.listStyle?.type === 'ordered';
195	
196	  const out = [...nodes];
197	  let i = 0;
198	  while (i < out.length) {
199	    if (!isOrdered(out[i]!)) {
200	      i++;
201	      continue;
202	    }
203	    let end = i;
204	    while (end < out.length && isOrdered(out[end]!)) end++;

