17	/** The column at which a node's children must be indented. */
18	export function childBaseCol(parent: OutlineNode | 'root'): number {
19	  if (parent === 'root' || parent.kind === 'heading') return 0;
20	  const indent = indentWidth(parent.lines[0] ?? '');
21	  if (parent.kind === 'list-item') return indent + markerWidth(parent);
22	  return indent; // paragraph: child lists sit at the paragraph's own indent
