25	function shiftLine(line: string, delta: number): string {
26	  if (line.trim() === '') return line;
27	  if (delta === 0) return line;
28	  if (delta > 0) return ' '.repeat(delta) + line;
29	  // Dedent: remove up to -delta columns of leading whitespace.
30	  let remaining = -delta;
31	  let i = 0;
32	  while (i < line.length && remaining > 0) {
33	    const ch = line[i];
34	    if (ch === ' ') remaining -= 1;
35	    else if (ch === '\t') remaining -= 4;
36	    else break;
37	    i++;
38	  }
39	  return line.slice(i);
40	}
