42	export function shiftSubtree(node: OutlineNode, delta: number): OutlineNode {
43	  if (delta === 0) return node;
44	  return {
45	    ...node,
46	    lines: node.lines.map((line) => shiftLine(line, delta)),
47	    children: node.children.map((child) => shiftSubtree(child, delta)),
48	  };
49	}
