51	/**
52	 * Re-encode a moved node for its destination: adjust indentation and, for
53	 * paragraph/list-item nodes, convert to `newKind` when the destination
54	 * context demands it. Children shift so their base column follows the
55	 * node's new content column.
56	 */
57	export function reencodeForDestination(
58	  node: OutlineNode,
59	  newKind: 'paragraph' | 'list-item' | undefined,
60	  targetIndent: number,
61	): OutlineNode {
62	  const currentIndent = indentWidth(node.lines[0] ?? '');
63	
64	  // Atoms and no-conversion cases: uniform shift.
65	  if (!newKind || newKind === node.kind) {
66	    return shiftSubtree(node, targetIndent - currentIndent);
67	  }
68	
69	  if (node.kind === 'paragraph' && newKind === 'list-item') {
70	    const pad = ' '.repeat(targetIndent);
71	    const contPad = ' '.repeat(targetIndent + 2);
72	    const lines = node.lines.map((line, i) =>
73	      i === 0 ? `${pad}- ${line.trimStart()}` : `${contPad}${line.trimStart()}`,
74	    );
75	    const oldChildBase = childBaseCol(node);
76	    const childDelta = targetIndent + 2 - oldChildBase;
77	    return {
78	      ...node,
79	      kind: 'list-item',
80	      listStyle: { type: 'bullet', marker: '-' },
81	      lines,
82	      children: node.children.map((child) => shiftSubtree(child, childDelta)),
83	    };
84	  }
85	
86	  if (node.kind === 'list-item' && newKind === 'paragraph') {
87	    const pad = ' '.repeat(targetIndent);
88	    const lines = node.lines.map((line, i) =>
89	      i === 0 ? `${pad}${line.replace(LIST_MARKER_RE, '')}` : `${pad}${line.trimStart()}`,
90	    );
91	    const oldChildBase = childBaseCol(node);
92	    const childDelta = targetIndent - oldChildBase;
93	    const result: OutlineNode = {
94	      ...node,
95	      kind: 'paragraph',
96	      lines,
97	      children: node.children.map((child) => shiftSubtree(child, childDelta)),
98	    };
99	    delete (result as { listStyle?: unknown }).listStyle;
100	    return result;
101	  }
102	
103	  return shiftSubtree(node, targetIndent - currentIndent);
104	}
