108	/** All heading nodes in a subtree (including the root node if a heading). */
109	export function subtreeHeadings(node: OutlineNode): OutlineNode[] {
110	  const out: OutlineNode[] = [];
111	  const walk = (n: OutlineNode): void => {
112	    if (n.kind === 'heading') out.push(n);
113	    n.children.forEach(walk);
