122	 */
123	export function headingWithLevel(node: OutlineNode, level: number): OutlineNode {
124	  const marker = '#'.repeat(level);
125	  let lines: string[];
126	  if (node.setext) {
127	    const text = (node.lines[0] ?? '').trim();
128	    lines = [`${marker} ${text}`];
129	  } else {
130	    const match = ATX_RE.exec(node.lines[0] ?? '');
131	    const text = match ? match[4]! : (node.lines[0] ?? '').trim();
132	    lines = [text === '' ? marker : `${marker} ${text}`];
133	  }
134	  const result: OutlineNode = { ...node, level, lines };
135	  delete (result as { setext?: unknown }).setext;
136	  return result;
137	}

